// O(n^2) 暴力贪心
void solve(int CASE)
{
	int n, k; cin >> n >> k;
	string s; cin >> s; s = ' ' + s;
	var ans = vector<bool>(n + 1);
	var cal = [&]()->int {
		int cnt = 0, res = 0;
		fa(i, 1, n)if(ans[i] == 0) {
			if (s[i] == '(')cnt++;
			else {
				if (cnt)cnt--, res++;
			}
		}
		return res;
		};
	int now = cal();
	fa(i, 1, n) {
		if (k == 0)break;
		ans[i] = 1;
		int to = cal();
		if (to == now)ans[i] = 0;
		else k--, now = to;
	}
	fa(i, 1, n)cout << ans[i]; 
	cout << endl;
	return;
}

// O(n) 套结论
void solve(int CASE)
{
	int n, k; cin >> n >> k;
	string s; cin >> s; s = ' ' + s;
	var pre = vector<int>(n + 2);
	var suf = vector<int>(n + 2);
	fa(i, 1, n)pre[i] = pre[i - 1] + (s[i] == '(');
	fb(i, n, 1)suf[i] = suf[i + 1] + (s[i] == ')');
	int mn = INF, mnpos = 0;
	fa(i, 0, n) {
		int now = pre[i] + suf[i + 1];
		if (now < mn) {
			mn = now;
			mnpos = i;
		}
	}
	var pos = vector<int>();
	fa(i, 1, mnpos)if (s[i] == '(')pos.pb(i);
	fa(i, mnpos + 1, n)if (s[i] == ')')pos.pb(i);
	string ans;
	fa(i, 1, n)ans.pb('0');
	for (int x : pos) {
		if (k == 0)break;
		k--;
		ans[x - 1] = '1';
	}
	cout << ans << endl;
	return;
}
